import json
from collections import defaultdict

with open('/home/archon/proj/Quot-Foundations/.leandag/dag.json') as f:
    d = json.load(f)
nodes = d['nodes']

by_chapter = defaultdict(lambda: {'total': 0, 'proved': 0, 'sorry': 0, 'unproved': []})
for n in nodes:
    if n.get('type') == 'lean_aux':
        continue
    chapter = n.get('tex_file', 'unknown').replace('chapters/', '')
    by_chapter[chapter]['total'] += 1
    if n.get('proved'):
        by_chapter[chapter]['proved'] += 1
    elif n.get('has_sorry'):
        by_chapter[chapter]['sorry'] += 1
    else:
        by_chapter[chapter]['unproved'].append(n['id'])

for ch, stats in sorted(by_chapter.items()):
    unp = len(stats['unproved'])
    print(f'{ch}: total={stats[\"total\"]}, proved={stats[\"proved\"]}, sorry={stats[\"sorry\"]}, unproved={unp}')
    if unp > 0 and unp <= 10:
        for u in stats['unproved']:
            print(f'  - {u}')
